using System.Text.Json;
namespace LifeOS.Shared.IntegrationConnectors.Gmail;
public enum GmailLifecycleState{ConfigurationMissing,ConfiguredDisconnected,ConnectedLocally,SearchPreviewed,SearchInProgress,SearchSucceeded,SearchEmpty,SearchPartial,SearchFailed,AuthenticationExpired,AccessRevoked,TokenCacheMissing,Disconnected,LocalCacheCleared}
public sealed class GmailLifecycleSnapshot{public GmailLifecycleState State{get;set;}=GmailLifecycleState.ConfigurationMissing;public DateTimeOffset? LastConnectionAttemptAt{get;set;}public DateTimeOffset? LastConnectedAt{get;set;}public DateTimeOffset? LastSearchAttemptAt{get;set;}public DateTimeOffset? LastSuccessfulSearchAt{get;set;}public DateTimeOffset? LastDisconnectAt{get;set;}public DateTimeOffset? LastCacheClearAt{get;set;}public DateTimeOffset? LastRangeFrom{get;set;}public DateTimeOffset? LastRangeTo{get;set;}public int LastResultCap{get;set;}public int LastReceived{get;set;}public int LastDuplicates{get;set;}public int LastSkipped{get;set;}public int LastCandidates{get;set;}public string LastProfile{get;set;}="";public string LastQuery{get;set;}="";public string LastSummary{get;set;}="No Gmail action recorded.";public string LastSanitizedError{get;set;}="";}
public static class GmailLifecycleStore{static readonly JsonSerializerOptions O=new(){WriteIndented=true};public static string FilePath=>Path.Combine(GmailConfigurationStore.DirectoryPath,"lifecycle.json");public static GmailLifecycleSnapshot Load(){try{return File.Exists(FilePath)?JsonSerializer.Deserialize<GmailLifecycleSnapshot>(File.ReadAllText(FilePath),O)??new():new();}catch{return new();}}public static void Save(GmailLifecycleSnapshot s){Directory.CreateDirectory(GmailConfigurationStore.DirectoryPath);File.WriteAllText(FilePath,JsonSerializer.Serialize(s,O));}public static void Disconnect(){GmailOAuthTokenStore.Delete();var s=Load();s.State=GmailLifecycleState.Disconnected;s.LastDisconnectAt=DateTimeOffset.Now;s.LastSummary="Local Gmail authorization removed. Imported communication evidence was retained.";Save(s);}public static void ClearCache(){GmailOAuthTokenStore.Delete();if(File.Exists(FilePath))File.Delete(FilePath);Save(new(){State=GmailLifecycleState.LocalCacheCleared,LastCacheClearAt=DateTimeOffset.Now,LastSummary="Local Gmail connector cache cleared. Imported communication evidence was retained."});}}
